package main

import (
	"net/http"
	"strings"
	"log"
)

type User struct {
	Username string
	Role     string // e.g. Admin, User
}

type CommandHandler func(*User, []string)

var (
	users      = make(map[string]*User)
	commands   = make(map[string]CommandHandler)
)

func kickHandler(u *User, args []string) {
	if u.Role != "Admin" {
		return
	}

	targetName := args[0]
	// Just as an example. You need to implement how to deal with the kicked user 
	if target, ok := users[targetName]; ok {
		log.Println(target.Username, "was kicked by", u.Username)
	}
}

func banHandler(u *User, args []string) {
	if u.Role != "Admin" {
		return
	}

	targetName := args[0]
	// Just as an example. You need to implement how to deal with the banned user
	if target, ok := users[targetName]; ok {
		log.Println(target.Username, "was banned by", u.Username)
	}
}

func giveItemsHandler(u *User, args []string) {
	if u.Role != "Admin" {
		return
	}

	targetName := args[0]
	items := args[1:]
	// Just as an example. You need to implement the logic for giving items
	log.Println("Give", items, "to", targetName, "by", u.Username)
}

func parseMessage(msg string, u *User) {
	parts := strings.Split(msg, " ")
	if handler, ok := commands[parts[0]]; ok {
		handler(u, parts[1:])
	}
}

func gameHandler(w http.ResponseWriter, r *http.Request) {
	username := r.Header.Get("Username")
	role := r.Header.Get("Role")

	user := &User{Username: username, Role: role}
	users[username] = user

	msg := r.URL.Query().Get("msg")
	parseMessage(msg, user)
}

func main() {
	commands["/kick"] = kickHandler
	commands["/ban"] = banHandler
	commands["/giveitems"] = giveItemsHandler
	
	http.HandleFunc("/game", gameHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}